const body = $input.first().json.body;
const msg = body?.data?.message;
const key = body?.data?.key;
if (!msg || key?.fromMe) return [];
const phone = (key?.remoteJid || '').replace('@s.whatsapp.net', '');
const text = (msg?.conversation || msg?.extendedTextMessage?.text || '').toLowerCase();
const pushName = body?.data?.pushName || 'there';
if (!phone || !text) return [];

const intents = [
  { intent: 'QUOTE_REQUEST', keywords: ['price', 'quote', 'cost', 'budget', 'how much', 'preco', 'orcamento', 'valor', 'quanto'] },
  { intent: 'SUPPORT', keywords: ['problem', 'broken', 'not working', 'help', 'issue', 'erro', 'problema', 'nao funciona', 'ajuda'] },
  { intent: 'SCHEDULING', keywords: ['schedule', 'appointment', 'visit', 'when', 'agendar', 'visita', 'horario', 'disponivel'] },
  { intent: 'GENERAL_INFO', keywords: ['info', 'details', 'what do you', 'services', 'informacao', 'servicos'] }
];

let intent = 'UNKNOWN';
for (const { intent: i, keywords } of intents) {
  if (keywords.some(k => text.includes(k))) { intent = i; break; }
}

const replies = {
  QUOTE_REQUEST: `Hi ${pushName}! 👋

Thank you for reaching out. To prepare a quote, I need a few details:

• What service are you looking for?
• Location / address
• Any specific requirements?

I'll get back to you with pricing within a few hours.`,
  SUPPORT: `Hi ${pushName},

Sorry to hear you're having an issue. Our support team has been notified and will contact you shortly.

In the meantime, please describe your problem in detail and we'll resolve it as quickly as possible.`,
  SCHEDULING: `Hi ${pushName}! 📅

We'd be happy to schedule a visit. Please let us know:

• Preferred date
• Preferred time (morning / afternoon)
• Address

We'll confirm availability and get back to you.`,
  GENERAL_INFO: `Hi ${pushName}! 👋

Here's a quick overview of our services:

• Security monitoring & alarm systems
• CCTV installation & support
• Patrol & guard services
• Facilities management

Feel free to ask about any specific service!`,
  UNKNOWN: `Hi ${pushName}! 👋

Thank you for reaching out. One of our team members will get back to you shortly.

If you need immediate assistance, please let us know!`
};

return [{ json: { phone, intent, reply: replies[intent], pushName } }];
